urlset:
{{- range (where .Data.Pages "Section" "!=" "gallery") -}}


            {{- .Permalink -}}

        {{- if not .Lastmod.IsZero -}}

                {{- .Lastmod.Format "2006-01-02T15:04:05-07:00" -}}

        {{- end -}}
        {{- with .Sitemap.ChangeFreq -}}

                {{- . -}}

        {{- end -}}

        {{- if ge .Sitemap.Priority 0.0 -}}
            {{- $weeks := div (sub now.Unix .Lastmod.Unix) 604800 -}}
            {{- $priority := sub 1 (div $weeks 10.0 ) -}}
            {{- if ge .Sitemap.Priority $priority -}}
                {{ .Sitemap.Priority }}
            {{- else -}}
                {{ $priority }}
            {{- end -}}
        {{- end -}}

        {{- /* image entries for Google image search: per-post OG card for
             posts, front-matter/site images for other pages. */ -}}
        {{- if eq .Type "posts" -}}
            {{- $ogCard := printf "/og/%s.png" (trim (path.Clean .RelPermalink) "/") | absURL -}}
            {{ $ogCard }}{{ .Title }}
        {{- else -}}
            {{- range first 3 (.Params.images | default .Site.Params.images | default slice) -}}
                {{ . | absURL }}
            {{- end -}}
        {{- end -}}

        {{- if .IsTranslated -}}
            {{- range .Translations -}}

            {{- end -}}

        {{- end -}}

{{- end -}}
